#include <bits/stdc++.h>
using namespace std;
int main(){
    string s;
    cin >> s;
    int k;
    cin >> k;
    int count = 0;
    for(int i = 0; i < s.length(); i++) {
        for(int j = i + 1; j <= s.length(); j++) {
            string substring = s.substr(i, j - i);
            set<char> distinct_chars(substring.begin(), substring.end());
            if(distinct_chars.size() == k) {
                count++;
            }
        }
    }
    cout << count << endl;
    return 0;
}
